export const ORACLE_CITATION_TOKEN = /\[(C|U):([A-Za-z0-9_-]+)\]/g;
export const ORACLE_CITATION_TOKEN_EXACT = /^\[(C|U):([A-Za-z0-9_-]+)\]$/;

const PREVIEW_CHARS = 240;
const SURROUNDING_CONTEXT_CHARS = 200;

export type ResolvedCitation =
  | {
      type: "conclusion";
      id: string;
      tier: string;
      url: string | null;
      preview: string;
    }
  | {
      type: "upload";
      id: string;
      title: string;
      url: string | null;
      anchor: string | null;
      preview: string;
    };

export type ResolvedCitationMap = Record<string, ResolvedCitation>;

export interface OracleCitationSource {
  type: "conclusion" | "upload";
  id: string;
  label: string;
  tier?: string;
  topic?: string;
  text: string;
  url?: string | null;
  anchor?: string | null;
}

export interface OracleUploadChunk {
  uploadId: string;
  chunkId?: string | null;
  chunkIndex: number;
  text: string;
}

export interface OracleCitationStats {
  citationsResolved: number;
  citationsUnresolved: number;
}

interface CitationMatch {
  token: string;
  kind: "C" | "U";
  fragment: string;
  index: number;
}

function preview(text: string): string {
  const cleaned = text.replace(/\s+/g, " ").trim();
  if (cleaned.length <= PREVIEW_CHARS) return cleaned;
  return `${cleaned.slice(0, PREVIEW_CHARS - 1).trimEnd()}...`;
}

function normalizeLookup(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9_-]+/g, "");
}

function tokenizeForOverlap(text: string): Set<string> {
  return new Set(
    text
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, " ")
      .split(/\s+/)
      .filter((token) => token.length >= 3),
  );
}

function lexicalOverlapScore(sourceText: string, answerContext: string): number {
  const sourceTokens = tokenizeForOverlap(sourceText);
  const contextTokens = tokenizeForOverlap(answerContext);
  if (sourceTokens.size === 0 || contextTokens.size === 0) return 0;

  let overlap = 0;
  for (const token of contextTokens) {
    if (sourceTokens.has(token)) overlap++;
  }
  return overlap / Math.sqrt(sourceTokens.size);
}

function uniqueCitationMatches(answer: string): CitationMatch[] {
  const seen = new Set<string>();
  const matches: CitationMatch[] = [];
  ORACLE_CITATION_TOKEN.lastIndex = 0;

  for (const match of answer.matchAll(ORACLE_CITATION_TOKEN)) {
    const token = match[0];
    const kind = match[1] as "C" | "U";
    const fragment = match[2]!;
    if (match.index === undefined || seen.has(token)) continue;
    seen.add(token);
    matches.push({ token, kind, fragment, index: match.index });
  }

  return matches;
}

function findSource(
  sources: OracleCitationSource[],
  kind: "C" | "U",
  fragment: string,
): OracleCitationSource | null {
  const expectedType = kind === "C" ? "conclusion" : "upload";
  const candidates = sources.filter((source) => source.type === expectedType);
  const direct = candidates.find((source) => source.id.startsWith(fragment));
  if (direct) return direct;

  // Backward-compatible fallback for pre-resolution prompts that used short
  // upload titles in [U:...] rather than upload id prefixes.
  if (kind === "U") {
    const normalizedFragment = normalizeLookup(fragment);
    return (
      candidates.find((source) =>
        normalizeLookup(source.label).startsWith(normalizedFragment),
      ) ?? null
    );
  }

  return null;
}

function bestUploadChunk(
  uploadId: string,
  answer: string,
  match: CitationMatch,
  chunks: OracleUploadChunk[],
  fallbackText: string,
): { anchor: string | null; text: string } {
  const before = answer.slice(
    Math.max(0, match.index - SURROUNDING_CONTEXT_CHARS),
    match.index,
  );
  const after = answer.slice(
    match.index + match.token.length,
    match.index + match.token.length + SURROUNDING_CONTEXT_CHARS,
  );
  const context = `${before} ${after}`;
  const candidates = chunks.filter((chunk) => chunk.uploadId === uploadId);

  let best: OracleUploadChunk | null = null;
  let bestScore = -1;
  for (const chunk of candidates) {
    const score = lexicalOverlapScore(chunk.text.slice(0, PREVIEW_CHARS * 2), context);
    if (score > bestScore) {
      best = chunk;
      bestScore = score;
    }
  }

  if (best && bestScore > 0) {
    return {
      anchor: best.chunkId ? `chunk-${best.chunkId}` : null,
      text: best.text,
    };
  }

  return { anchor: null, text: fallbackText };
}

export function conclusionCitationPath(id: string): string {
  return `/conclusions/${encodeURIComponent(id)}`;
}

export function uploadCitationPath(id: string): string {
  return `/transcripts/${encodeURIComponent(id)}`;
}

export function citationHref(citation: ResolvedCitation): string | null {
  if (!citation.url) return null;
  if (citation.type !== "upload" || !citation.anchor) return citation.url;
  return `${citation.url}?anchor=${encodeURIComponent(citation.anchor)}`;
}

export function maskCitationToken(token: string): string {
  const parsed = ORACLE_CITATION_TOKEN_EXACT.exec(token);
  if (!parsed) return "[citation:***]";
  const kind = parsed[1];
  const id = parsed[2]!;
  if (id.length <= 4) return `[${kind}:***]`;
  return `[${kind}:${id.slice(0, 2)}***${id.slice(-2)}]`;
}

export function resolveOracleCitations(params: {
  answer: string;
  sources: OracleCitationSource[];
  uploadChunks?: OracleUploadChunk[];
}): { citations: ResolvedCitationMap } & OracleCitationStats {
  const uploadChunks = params.uploadChunks ?? [];
  const citations: ResolvedCitationMap = {};
  let citationsResolved = 0;
  let citationsUnresolved = 0;

  for (const match of uniqueCitationMatches(params.answer)) {
    const source = findSource(params.sources, match.kind, match.fragment);

    if (!source) {
      citationsUnresolved++;
      citations[match.token] =
        match.kind === "C"
          ? {
              type: "conclusion",
              id: match.fragment,
              tier: "unknown",
              url: null,
              preview: "",
            }
          : {
              type: "upload",
              id: match.fragment,
              title: match.fragment,
              url: null,
              anchor: null,
              preview: "",
            };
      continue;
    }

    citationsResolved++;
    if (source.type === "conclusion") {
      citations[match.token] = {
        type: "conclusion",
        id: source.id,
        tier: source.tier || source.label,
        url: conclusionCitationPath(source.id),
        preview: preview(source.text),
      };
      continue;
    }

    const best = bestUploadChunk(
      source.id,
      params.answer,
      match,
      uploadChunks,
      source.text,
    );
    citations[match.token] = {
      type: "upload",
      id: source.id,
      title: source.label,
      url: uploadCitationPath(source.id),
      anchor: best.anchor,
      preview: preview(best.text),
    };
  }

  return { citations, citationsResolved, citationsUnresolved };
}

import { redirect } from "next/navigation";
import { db } from "@/lib/db";
import { getFounder } from "@/lib/auth";

export const dynamic = "force-dynamic";

const STATUS_PILL: Record<string, { bg: string; fg: string; label: string }> = {
  RETRACTED: { bg: "#5b1414", fg: "#ffd1d1", label: "retracted" },
  CORRECTED: { bg: "#5b3414", fg: "#ffe2c2", label: "corrected" },
  EXPIRED: { bg: "#3a3a3a", fg: "#dcdcdc", label: "expired" },
  DISPUTED: { bg: "#5a4a14", fg: "#ffe9a8", label: "disputed" },
};

function pillStyle(status: string) {
  return STATUS_PILL[status] ?? { bg: "#222", fg: "#ddd", label: status.toLowerCase() };
}

export default async function SourceTriagePage() {
  const founder = await getFounder();
  if (!founder) redirect("/login");

  const items = await db.sourceTriageItem.findMany({
    where: {
      organizationId: founder.organizationId,
      decision: "pending",
    },
    orderBy: { createdAt: "desc" },
    take: 100,
  });

  const conclusionIds = Array.from(new Set(items.map((i) => i.conclusionId)));
  const conclusions = conclusionIds.length
    ? await db.conclusion.findMany({
        where: { id: { in: conclusionIds }, organizationId: founder.organizationId },
        select: { id: true, text: true, confidenceTier: true },
      })
    : [];
  const conclusionMap = new Map(conclusions.map((c) => [c.id, c]));

  const standingIds = Array.from(new Set(items.map((i) => i.standingId)));
  const standings = standingIds.length
    ? await db.sourceStanding.findMany({
        where: { id: { in: standingIds }, organizationId: founder.organizationId },
        select: {
          id: true,
          reason: true,
          poller: true,
          observedAt: true,
          noticeSourceId: true,
        },
      })
    : [];
  const standingMap = new Map(standings.map((s) => [s.id, s]));

  return (
    <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
      <h1
        style={{
          fontFamily: "'Cinzel', serif",
          color: "var(--gold)",
          letterSpacing: "0.08em",
        }}
      >
        Source triage
      </h1>
      <p style={{ color: "var(--parchment-dim)", marginBottom: "1.5rem" }}>
        Sources cited by firm conclusions whose standing has changed.
        Confirm to propagate the revision (evidence weight removed) or
        override to keep the existing weight with a stated reason.
      </p>

      {items.length === 0 ? (
        <p style={{ color: "var(--parchment-dim)" }}>
          No pending source-standing events.
        </p>
      ) : (
        <ul
          style={{
            listStyle: "none",
            padding: 0,
            margin: 0,
            display: "flex",
            flexDirection: "column",
            gap: "0.85rem",
          }}
        >
          {items.map((item) => {
            const c = conclusionMap.get(item.conclusionId);
            const s = standingMap.get(item.standingId);
            const pill = pillStyle(item.status);
            return (
              <li
                key={item.id}
                className="portal-card"
                style={{ padding: "1rem 1.25rem" }}
                data-testid="source-triage-row"
              >
                <div
                  style={{
                    display: "flex",
                    gap: "0.75rem",
                    alignItems: "baseline",
                    flexWrap: "wrap",
                  }}
                >
                  <span
                    style={{
                      background: pill.bg,
                      borderRadius: "999px",
                      color: pill.fg,
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.65rem",
                      letterSpacing: "0.1em",
                      padding: "0.15rem 0.55rem",
                      textTransform: "uppercase",
                    }}
                  >
                    {pill.label}
                  </span>
                  <code style={{ color: "var(--parchment-dim)", fontSize: "0.78rem" }}>
                    {item.sourceId}
                  </code>
                  {s ? (
                    <span style={{ color: "var(--parchment-dim)", fontSize: "0.7rem" }}>
                      via {s.poller} ·{" "}
                      {new Date(s.observedAt).toISOString().slice(0, 10)}
                    </span>
                  ) : null}
                </div>

                {s?.reason ? (
                  <p style={{ color: "var(--parchment)", fontSize: "0.85rem", marginTop: "0.45rem" }}>
                    {s.reason}
                  </p>
                ) : null}

                <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem", marginTop: "0.6rem" }}>
                  Affects conclusion:{" "}
                  <a
                    href={`/conclusions/${item.conclusionId}`}
                    style={{ color: "var(--gold)" }}
                  >
                    {c?.text?.slice(0, 140) ?? item.conclusionId}
                  </a>
                  {c ? (
                    <span style={{ marginLeft: "0.5rem", fontSize: "0.7rem" }}>
                      ({c.confidenceTier})
                    </span>
                  ) : null}
                </p>

                {s?.noticeSourceId ? (
                  <p style={{ color: "var(--parchment-dim)", fontSize: "0.7rem", marginTop: "0.35rem" }}>
                    Notice provenance: <code>{s.noticeSourceId}</code>
                  </p>
                ) : null}

                <form
                  action="/api/source-triage/decide"
                  method="POST"
                  style={{ display: "flex", gap: "0.5rem", marginTop: "0.75rem", flexWrap: "wrap" }}
                >
                  <input type="hidden" name="id" value={item.id} />
                  <button
                    name="decision"
                    value="confirmed"
                    type="submit"
                    style={{
                      background: "var(--gold)",
                      border: "none",
                      borderRadius: "4px",
                      color: "#1a1208",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
                      textTransform: "uppercase",
                    }}
                  >
                    Confirm propagation
                  </button>
                  <button
                    name="decision"
                    value="overridden"
                    type="submit"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--gold-dim)",
                      borderRadius: "4px",
                      color: "var(--gold)",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
                      textTransform: "uppercase",
                    }}
                  >
                    Override (keep weight)
                  </button>
                  <button
                    name="decision"
                    value="dismissed"
                    type="submit"
                    style={{
                      background: "transparent",
                      border: "1px solid var(--parchment-dim)",
                      borderRadius: "4px",
                      color: "var(--parchment-dim)",
                      cursor: "pointer",
                      fontFamily: "'IBM Plex Mono', monospace",
                      fontSize: "0.72rem",
                      letterSpacing: "0.08em",
                      padding: "0.4rem 0.85rem",
                      textTransform: "uppercase",
                    }}
                  >
                    Dismiss
                  </button>
                </form>
              </li>
            );
          })}
        </ul>
      )}
    </main>
  );
}

