41	  | "active"
42	  | "retracted"
43	  | "corrected"
44	  | "disputed"
45	  | "expired";
46	
47	const STANDING_STYLE: Record<Exclude<SourceStanding, "active">, { bg: string; fg: string; label: string }> = {
48	  retracted: { bg: "#5b1414", fg: "#ffd1d1", label: "Retracted" },
49	  corrected: { bg: "#5b3414", fg: "#ffe2c2", label: "Corrected" },
50	  expired: { bg: "#3a3a3a", fg: "#dcdcdc", label: "Expired" },
51	  disputed: { bg: "#5a4a14", fg: "#ffe9a8", label: "Disputed" },
52	};
53	
54	function normalizedStanding(citation: CitationWithVisibility): SourceStanding {
55	  const raw = (citation.source_standing ?? citation.sourceStanding ?? "active")
56	    .toString()
57	    .trim()
58	    .toLowerCase();
59	  if (raw === "retracted" || raw === "corrected" || raw === "disputed" || raw === "expired") {
60	    return raw;
61	  }
62	  return "active";
63	}
64	
65	function standingReason(citation: CitationWithVisibility): string {
66	  return (citation.standing_reason ?? citation.standingReason ?? "").toString().trim();
67	}
68	
69	interface CitationPopoverProps {
70	  open: boolean;
71	  onClose: () => void;
72	  anchorRef: RefObject<HTMLElement | null>;
73	  citation: CitationWithVisibility;
74	  conclusionText: string;
75	  publicUrl: string | null;
76	  id?: string;
77	}
78	
79	interface PopoverPosition {
80	  left: number;
81	  top: number;
82	}
83	
84	const FOCUSABLE_SELECTOR =
85	  'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])';
86	const ESTIMATED_HEIGHT = 250;
87	const MARGIN = 12;
88	const WIDTH = 360;
89	const POPOVER_Z_INDEX = 10020;
90	
91	const shellStyle: CSSProperties = {
92	  background: "var(--currents-bg-elevated)",
93	  border: "1px solid var(--currents-border)",
94	  borderRadius: "6px",
95	  boxShadow: "0 18px 45px rgba(0, 0, 0, 0.38)",
96	  color: "var(--currents-parchment)",
97	  maxWidth: `calc(100vw - ${MARGIN * 2}px)`,
98	  padding: "0.85rem",
99	  position: "fixed",
100	  width: `${WIDTH}px`,
101	  zIndex: POPOVER_Z_INDEX,
102	};
103	
104	const captionStyle: CSSProperties = {
105	  color: "var(--currents-muted)",
106	  fontFamily: "'IBM Plex Mono', monospace",
107	  fontSize: "0.68rem",
108	  letterSpacing: "0.12em",
109	  textTransform: "uppercase",
110	};
111	
112	const titleStyle: CSSProperties = {
113	  color: "var(--currents-parchment)",
114	  fontFamily: "'EB Garamond', serif",
115	  fontSize: "1rem",
116	  lineHeight: 1.25,
117	  margin: "0.25rem 0 0",
118	};
119	
120	const bodyStyle: CSSProperties = {
121	  color: "var(--currents-parchment-dim)",
122	  fontSize: "0.9rem",
123	  lineHeight: 1.55,
124	  marginTop: "0.65rem",
125	  maxHeight: "16rem",
126	  overflow: "auto",
127	};
128	
129	const linkStyle: CSSProperties = {
130	  color: "var(--currents-gold)",
131	  display: "inline-flex",
132	  fontSize: "0.84rem",
133	  marginTop: "0.7rem",
134	  textDecoration: "none",
135	};
136	
137	const privateNoteStyle: CSSProperties = {
138	  borderTop: "1px solid var(--currents-border)",
139	  color: "var(--currents-muted)",
140	  fontSize: "0.78rem",
141	  lineHeight: 1.45,
142	  margin: "0.75rem 0 0",
143	  paddingTop: "0.6rem",
144	};
145	
146	function citationKind(citation: PublicCitation): string {
147	  const kind = citation.source_kind.trim().toLowerCase();
148	  if (kind === "claim") return "opinion";
149	  if (kind === "conclusion") return "firm conclusion";
150	  return kind || "firm source";
151	}
152	
153	function citationTitle(citation: CitationWithVisibility): string {
154	  return (
155	    citation.conclusion_title?.trim() ||
156	    citation.conclusionTitle?.trim() ||
157	    citationKind(citation)
158	  );
159	}
160	
161	function normalizedVisibility(citation: CitationWithVisibility): string {
162	  return (citation.source_visibility ?? citation.visibility ?? "")
163	    .trim()
164	    .toLowerCase()
165	    .replace(/-/g, "_");
166	}
167	
168	function canExposePublicUrl(citation: CitationWithVisibility, publicUrl: string | null): boolean {
169	  return Boolean(publicUrl?.trim()) && normalizedVisibility(citation) === "org";
170	}
171	
172	function safeHref(rawUrl: string | null): string | null {
173	  const trimmed = rawUrl?.trim();
174	  if (!trimmed) return null;
175	  if (trimmed.startsWith("/") && !trimmed.startsWith("//")) return trimmed;
176	  try {
177	    const url = new URL(trimmed);
178	    if (url.protocol === "http:" || url.protocol === "https:") return url.toString();
179	  } catch {
180	    return null;
181	  }
182	  return null;
183	}
184	
185	function isHTMLElement(value: unknown): value is HTMLElement {
186	  if (!value || typeof value !== "object") return false;
187	  if (typeof HTMLElement === "undefined") {
188	    return typeof (value as HTMLElement).focus === "function";
189	  }
190	  return value instanceof HTMLElement;
191	}
192	
193	function focusableElements(container: HTMLElement): HTMLElement[] {
194	  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)).filter(
195	    (element) => !element.hasAttribute("disabled") && element.tabIndex !== -1,
196	  );
197	}
198	
199	function anchorIsOutsideViewport(anchor: HTMLElement): boolean {
200	  const rect = anchor.getBoundingClientRect();
201	  const viewportWidth =
202	    window.innerWidth || document.documentElement?.clientWidth || WIDTH;
203	  const viewportHeight =
204	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
205	  return (
206	    rect.bottom < 0 ||
207	    rect.top > viewportHeight ||
208	    rect.right < 0 ||
209	    rect.left > viewportWidth
210	  );
211	}
212	
213	function positionFor(anchor: HTMLElement, dialog: HTMLElement | null): PopoverPosition {
214	  const rect = anchor.getBoundingClientRect();
215	  const viewportWidth =
216	    window.innerWidth || document.documentElement?.clientWidth || WIDTH + MARGIN * 2;
217	  const viewportHeight =
218	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
219	  const height = dialog?.offsetHeight || ESTIMATED_HEIGHT;
220	  const preferredTop = rect.top - height - 10;
221	  const top =
222	    preferredTop >= MARGIN
223	      ? preferredTop
224	      : Math.min(rect.bottom + 10, Math.max(MARGIN, viewportHeight - height - MARGIN));
225	  const centeredLeft = rect.left + rect.width / 2 - WIDTH / 2;
226	  const left = Math.min(
227	    Math.max(MARGIN, centeredLeft),
228	    Math.max(MARGIN, viewportWidth - WIDTH - MARGIN),
229	  );
230	  return { left, top };
231	}
232	
233	interface CredibilityStripProps {
234	  credibility: SourceCredibilityPayload;
235	}
236	
237	function CredibilityStrip({ credibility }: CredibilityStripProps) {
238	  const score = Math.max(0, Math.min(100, credibility.score_100));
239	  const fill = scoreBandColor(score);
240	  const bandLabel = scoreBandLabel(score);
241	  const summary = summaryLine(credibility);
242	  const tooltip = credibility.confident
243	    ? summary
244	    : `${summary} — ${unconfidentCaveat(credibility)}`;
245	
246	  return (
247	    <div
248	      data-testid="source-credibility"
249	      style={{
250	        borderTop: "1px solid var(--currents-border)",
251	        marginTop: "0.7rem",
252	        paddingTop: "0.55rem",
253	      }}
254	      title={tooltip}
255	    >
256	      <div
257	        style={{
258	          alignItems: "baseline",
259	          color: "var(--currents-muted)",
260	          display: "flex",
261	          fontFamily: "'IBM Plex Mono', monospace",
262	          fontSize: "0.65rem",
263	          justifyContent: "space-between",
264	          letterSpacing: "0.1em",
265	          textTransform: "uppercase",
266	        }}
267	      >
268	        <span>Source credibility</span>
269	        <span style={{ color: "var(--currents-parchment-dim)" }}>
270	          {sourceTypeLabel(credibility.source_type)}
271	        </span>
272	      </div>
273	      <div
274	        aria-label={
275	          credibility.confident
276	            ? `Source credibility ${score} of 100 (${bandLabel})`
277	            : `Source credibility unsettled — ${credibility.n_updates} of ${credibility.min_updates_for_confidence} updates`
278	        }
279	        role="img"
280	        style={{
281	          background: "rgba(255,255,255,0.06)",
282	          borderRadius: "3px",
283	          height: "8px",
284	          marginTop: "0.35rem",
285	          overflow: "hidden",
286	          position: "relative",
287	          width: "100%",
288	        }}
289	      >
290	        <div
291	          data-testid="source-credibility-fill"
292	          style={{
293	            background: credibility.confident ? fill : "rgba(255,255,255,0.18)",
294	            height: "100%",
295	            transition: "width 200ms ease",
296	            width: `${score}%`,
297	          }}
298	        />
299	      </div>
300	      <div
301	        style={{
302	          color: "var(--currents-parchment-dim)",
303	          display: "flex",
304	          fontFamily: "'IBM Plex Mono', monospace",
305	          fontSize: "0.7rem",
306	          justifyContent: "space-between",
307	          marginTop: "0.3rem",
308	        }}
309	      >
310	        <span data-testid="source-credibility-score">
311	          {credibility.confident
312	            ? `${score.toFixed(score % 1 === 0 ? 0 : 1)} / 100`
313	            : `n=${credibility.n_updates} updates`}
314	        </span>
315	        <span style={{ color: "var(--currents-muted)" }}>{summary}</span>
316	      </div>
317	      {!credibility.confident ? (
318	        <p
319	          style={{
320	            color: "var(--currents-muted)",
321	            fontSize: "0.72rem",
322	            lineHeight: 1.4,
323	            margin: "0.35rem 0 0",
324	          }}
325	        >
326	          {unconfidentCaveat(credibility)}
327	        </p>
328	      ) : null}
329	    </div>
330	  );
331	}
332	
333	export default function CitationPopover({
334	  open,
335	  onClose,
336	  anchorRef,
337	  citation,
338	  conclusionText,
339	  publicUrl,
340	  id,
341	}: CitationPopoverProps) {
342	  const rawId = useId();
343	  const popoverId = id ?? `citation-popover-${rawId.replace(/:/g, "")}`;
344	  const dialogRef = useRef<HTMLDivElement | null>(null);
345	  const [position, setPosition] = useState<PopoverPosition | null>(null);
346	  const href = canExposePublicUrl(citation, publicUrl) ? safeHref(publicUrl) : null;
347	  const text =
348	    conclusionText.trim() ||
349	    citation.quoted_span.trim() ||
350	    "Firm conclusion text unavailable.";
351	
352	  const updatePosition = useCallback(() => {
353	    const anchor = anchorRef.current;
354	    if (!anchor) {
355	      onClose();
356	      return;
357	    }
358	    if (anchorIsOutsideViewport(anchor)) {
359	      onClose();
360	      return;
361	    }
362	    setPosition(positionFor(anchor, dialogRef.current));
363	  }, [anchorRef, onClose]);
364	
365	  useEffect(() => {
366	    if (!open) return;
367	    updatePosition();
368	    window.addEventListener("resize", updatePosition);
369	    window.addEventListener("scroll", updatePosition, true);
370	    return () => {
371	      window.removeEventListener("resize", updatePosition);
372	      window.removeEventListener("scroll", updatePosition, true);
373	    };
374	  }, [open, updatePosition]);
375	
376	  useEffect(() => {
377	    if (!open) return;
378	
379	    const handlePointerDown = (event: MouseEvent | TouchEvent) => {
380	      const target = event.target as Node | null;
381	      if (!target) return;
382	      if (dialogRef.current?.contains(target)) return;
383	      if (anchorRef.current?.contains(target)) return;
384	      onClose();
385	    };
386	
387	    const handleKeyDown = (event: KeyboardEvent) => {
388	      if (event.key === "Escape") {
389	        event.preventDefault();
390	        onClose();
391	      }
392	    };
393	
394	    document.addEventListener("mousedown", handlePointerDown);
395	    document.addEventListener("touchstart", handlePointerDown);
396	    document.addEventListener("keydown", handleKeyDown);
397	    return () => {
398	      document.removeEventListener("mousedown", handlePointerDown);
399	      document.removeEventListener("touchstart", handlePointerDown);
400	      document.removeEventListener("keydown", handleKeyDown);
401	    };
402	  }, [anchorRef, onClose, open]);
403	
404	  useEffect(() => {
405	    if (!open) return;
406	    const previousFocus = document.activeElement;
407	    const frame = window.requestAnimationFrame(() => {
408	      const dialog = dialogRef.current;
409	      if (!dialog) return;
410	      const [first] = focusableElements(dialog);
411	      (first ?? dialog).focus();
412	    });
413	
414	    return () => {
415	      window.cancelAnimationFrame(frame);
416	      if (isHTMLElement(previousFocus)) previousFocus.focus();
417	    };
418	  }, [open]);
419	
420	  const trapFocus = (event: ReactKeyboardEvent<HTMLDivElement>) => {
421	    if (event.key !== "Tab") return;
422	    const dialog = dialogRef.current;
423	    if (!dialog) return;
424	    const focusable = focusableElements(dialog);
425	    if (!focusable.length) {
426	      event.preventDefault();
427	      dialog.focus();
428	      return;
429	    }
430	
431	    const first = focusable[0];
432	    const last = focusable[focusable.length - 1];
433	    const active = document.activeElement;
434	    if (event.shiftKey && active === first) {
435	      event.preventDefault();
436	      last.focus();
437	    } else if (!event.shiftKey && active === last) {
438	      event.preventDefault();
439	      first.focus();
440	    }
441	  };
442	
443	  if (!open || typeof document === "undefined") return null;
444	
445	  const standing = normalizedStanding(citation);
446	  const standingMeta = standing === "active" ? null : STANDING_STYLE[standing];
447	  const reason = standingReason(citation);
448	  const credibility = normalizeCredibilityPayload(
449	    citation.source_credibility ?? citation.sourceCredibility ?? null,
450	  );
451	
452	  return createPortal(
453	    <div
454	      aria-modal="false"
455	      id={popoverId}
456	      onKeyDown={trapFocus}
457	      ref={dialogRef}
458	      role="dialog"
459	      style={{
460	        ...shellStyle,
461	        left: `${position?.left ?? MARGIN}px`,
462	        opacity: position ? 1 : 0,
463	        top: `${position?.top ?? MARGIN}px`,
464	      }}
465	      tabIndex={-1}
466	    >
467	      <div
468	        style={{
469	          alignItems: "start",
470	          display: "flex",
471	          gap: "0.75rem",
472	          justifyContent: "space-between",
473	        }}
474	      >
475	        <div>
476	          <div style={captionStyle}>{citationKind(citation)}</div>
477	          <h2 style={titleStyle}>{citationTitle(citation)}</h2>
478	          {standingMeta ? (
479	            <div style={{ marginTop: "0.4rem" }}>
480	              <span
481	                aria-label={`Source standing: ${standingMeta.label}`}
482	                data-testid="source-standing-pill"
483	                style={{
484	                  background: standingMeta.bg,
485	                  border: "1px solid rgba(0,0,0,0.35)",
486	                  borderRadius: "999px",
487	                  color: standingMeta.fg,
488	                  display: "inline-block",
489	                  fontFamily: "'IBM Plex Mono', monospace",
490	                  fontSize: "0.65rem",
491	                  letterSpacing: "0.1em",
492	                  padding: "0.15rem 0.55rem",
493	                  textTransform: "uppercase",
494	                }}
495	              >
496	                {standingMeta.label}
497	              </span>
498	              {reason ? (
499	                <span
500	                  style={{
501	                    color: "var(--currents-muted)",
502	                    fontSize: "0.72rem",
503	                    marginLeft: "0.55rem",
504	                  }}
505	                >
506	                  {reason}
507	                </span>
508	              ) : null}
509	              {standing === "retracted" || standing === "corrected" ? (
510	                <a
511	                  href="/methodology#source-standing"
512	                  style={{
513	                    color: "var(--currents-gold)",
514	                    display: "inline-block",
515	                    fontSize: "0.72rem",
516	                    marginLeft: "0.55rem",
517	                    textDecoration: "underline",
518	                  }}
519	                >
520	                  this source has been retracted →
521	                </a>
522	              ) : null}
523	            </div>
524	          ) : null}
525	        </div>
526	        <button
527	          aria-label="Close citation"
528	          onClick={onClose}
529	          style={{
530	            background: "transparent",
531	            border: "1px solid var(--currents-border)",
532	            borderRadius: "4px",
533	            color: "var(--currents-parchment-dim)",
534	            cursor: "pointer",
535	            fontSize: "0.8rem",
536	            lineHeight: 1,
537	            padding: "0.25rem 0.35rem",
538	          }}
539	          type="button"
540	        >
541	          ×
542	        </button>
543	      </div>
544	
545	      {credibility ? (
546	        <CredibilityStrip credibility={credibility} />
547	      ) : null}
548	
549	      <div style={bodyStyle}>{renderSafeMarkdown(text)}</div>
550	
551	      {href ? (
552	        <a href={href} rel="noopener nofollow ugc" style={linkStyle} target="_blank">
553	          Open the public conclusion →
554	        </a>
555	      ) : (
556	        <p style={privateNoteStyle}>
557	          Source recorded by the firm; not publicly available.
558	        </p>
559	      )}
560	    </div>,
561	    document.body,
562	  );
563	}
