      style={{ marginTop: "0.4rem" }}
      title={summary}
    >
      <span
        aria-label={`Citation verdict: ${style.label}`}
        data-testid="citation-verdict-pill"
        style={{
          background: style.bg,
          border: "1px solid rgba(0,0,0,0.35)",
          borderRadius: "999px",
