      ) : null}
      <p
        style={{
          color: "var(--currents-parchment-dim)",
          fontSize: "0.72rem",
          lineHeight: 1.4,
          margin: "0.35rem 0 0",
        }}
      >
        {summary}
      </p>
    </div>
  );
}

interface CredibilityStripProps {
