            : `Source credibility unsettled — ${credibility.n_updates} of ${credibility.min_updates_for_confidence} updates`
        }
        role="img"
        style={{
          background: "rgba(255,255,255,0.06)",
          borderRadius: "3px",
          height: "8px",
          marginTop: "0.35rem",
          overflow: "hidden",
          position: "relative",
          width: "100%",
        }}
      >
        <div
          data-testid="source-credibility-fill"
          style={{
