              display: "flex",
              flexDirection: "column",
              gap: "0.85rem",
            }}
          >
            {standingItems.map((item) => {
              const c = conclusionMap.get(item.conclusionId);
              const s = item.standingId ? standingMap.get(item.standingId) : null;
