                    style={{
                      display: "flex",
                      gap: "0.75rem",
                      alignItems: "baseline",
                      flexWrap: "wrap",
                    }}
                  >
                    <span
                      style={{
                        background: pill.bg,
                        borderRadius: "999px",
                        color: pill.fg,
                        fontFamily: "'IBM Plex Mono', monospace",
                        fontSize: "0.65rem",
                        letterSpacing: "0.1em",
                        padding: "0.15rem 0.55rem",
                        textTransform: "uppercase",
                      }}
                    >
                      {pill.label}
                    </span>
                    <code style={{ color: "var(--parchment-dim)", fontSize: "0.78rem" }}>
                      {item.sourceId}
